.l-wave-squares-rose span{width:var(--lc-size,12px);height:var(--lc-size,12px);background:var(--lc-color,#5b8def);border-radius:3px;animation:l-wave-squares-rose-w var(--lc-speed,1.2s) ease-in-out infinite}
.l-wave-squares-rose span:nth-child(2){animation-delay:.15s}
.l-wave-squares-rose span:nth-child(3){animation-delay:.3s}
.l-wave-squares-rose span:nth-child(4){animation-delay:.45s}
@keyframes l-wave-squares-rose-w{0%,100%{transform:translateY(0)}50%{transform:translateY(calc(var(--lc-size,12px)*1.6))}}

